import React, { useEffect, useState } from "react";
import "./Header.css";
import defaultPhoto from "../../assets/avatar1.jpg"; // Foto padrão

function Header() {
    const [user, setUser] = useState(null);

    useEffect(() => {
        // Buscar dados do usuário no localStorage
        const storedUser = localStorage.getItem("user");
        if (storedUser) {
            setUser(JSON.parse(storedUser));
        }
    }, []);

    return (
        <div className="header">
            <div className="profile-content">
                <img 
                    src={user?.profilePic || defaultPhoto} 
                    alt="foto de perfil" 
                />
                <div className="info">
                    <h3>{user?.name || "Usuário"}</h3>
                    <span>Nível Passista</span>
                </div>
            </div>
            <div className="cash" data-aos="fade-down">
                <h3>Saldo capiba</h3>
                <span>C${user?.capiba || 0}</span>
            </div>
        </div>
    );
}

export default Header;
